mapper.select:
/* TM_ECS_INTN_USR_ATHR_Dao_retriebeUsrAthrGrp */ SELECT AT.athr_id, AT.athr_nm, UI.empno AS usr_id, UI.korname AS usr_nm, UI.empno AS usr_empno, UI.buscd AS usr_dept_cd, UI.dept AS usr_dept_nm, UI.calcd AS usr_ofcps_cd, UI.posit AS usr_ofcps_nm, UI.zgrcd AS usr_jgrd_cd, UI.grade AS usr_jgrd_nm, AT.applc_strt_de, AT.applc_end_de FROM HRM.vm_hr01601 UI, (SELECT C.athr_id, C.athr_nm, B.usr_id, B.applc_strt_de, B.applc_end_de, C.use_yn FROM tm_ecs_intn_usr_athr B, tm_ecs_intn_athr C WHERE B.athr_id = C.athr_id
/*권한그룹으로 검색을 했을 경우*/ AND C.athr_id = #{athrId}
) AT WHERE 1 = 1 /*권한그룹으로 검색을 했을 경우*/ AND UI.empno = AT.usr_id
AND UI.dept LIKE '%' || #{usrDeptNm} || '%' --부서명으로 검색
AND UI.korname LIKE '%' || #{usrNm} || '%' --사용자명으로 검색

mapper.update:
/* TM_ECS_INTN_USR_ATHR_Dao_updateUsrAhtrGrpMng */
UPDATE
	tm_ecs_intn_usr_athr
SET
	applc_strt_de = #{applcStrtDe},
	applc_end_de = #{applcEndDe},
	last_updt_dt = SYSDATE,
	last_updusr_id = #{lastUpdusrId}
WHERE
	usr_id = #{usrId}
	AND athr_id = #{athrId}

mapper.delete:
/* TM_ECS_INTN_USR_ATHR_Dao_deleteUsrAhtrMng */
DELETE FROM
	tm_ecs_intn_usr_athr
WHERE
	usr_id = #{usrId}
	AND athr_id = #{athrId}

mapper.select:
/* TM_ECS_INTN_USR_ATHR_Dao_selectUsrAthrUse */
SELECT
	A.usr_id,
	A.athr_id
FROM
	tm_ecs_intn_usr_athr A
WHERE
	A.usr_id = #{usrId}
	AND A.athr_id = #{athrId}

/* 시스템 구분 조회 */
/* TM_ECS_INTN_USR_ATHR_Dao_retrieveUsrAthr */
SELECT
	B.usr_id,
	A.athr_id,
	A.athr_nm,
	A.athr_dc
FROM
	tm_ecs_intn_athr A,
	tm_ecs_intn_usr_athr B
WHERE
	A.athr_id = B.athr_id
	AND A.intn_sys_div_cd = #{intnSysDivCd}
	AND B.usr_id = #{usrId}

	/* 권한명을 지정 후 검색을 할때 */
	AND B.athr_id = #{athrId}

ORDER BY
	A.athr_id
